1827	\leanok
1828	[The restricted-diagonal comorphism is surjective]
1829	  \label{lem:gr_diagonalRingMap_surjective}
1830	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap_surjective}
1831	  \uses{lem:gr_diagonalRingMap_left, lem:gr_diagonalRingMap_right, lem:gr_transitionPreMap_minorDet_swap_mul}
1832	  The comorphism \(\delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}}
1833	  \mathbb{Z}[X^J] \to R^I_J\) (\cref{def:gr_diagonalRingMap}) is surjective.
