1835	\begin{proof}
1836	  \uses{lem:gr_diagonalRingMap_left, lem:gr_diagonalRingMap_right, lem:gr_transitionPreMap_minorDet_swap_mul}
1837	  \leanok
1838	  Let \(z \in R^I_J\). Since \(R^I_J = \mathbb{Z}[X^I, 1/P^I_J]\) is the
1839	  localisation of \(R^I = \mathbb{Z}[X^I]\) away from \(P^I_J\), surjectivity of
1840	  the localisation map provides \(a \in R^I\) and \(n \in \mathbb{N}\) with
1841	  \[
1842	    z \cdot (P^I_J)^n \;=\; \mathrm{alg}_{R^I \to R^I_J}(a).
1843	  \]
1844	  Consider the witness \(a \otimes (P^J_I)^n \in \mathbb{Z}[X^I]
1845	  \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]\). Using multiplicativity together with
1846	  \cref{lem:gr_diagonalRingMap_left} and \cref{lem:gr_diagonalRingMap_right},
1847	  \[
1848	    \delta_{I,J}\bigl(a \otimes (P^J_I)^n\bigr)
1849	      = \mathrm{alg}_{R^I \to R^I_J}(a) \cdot \tilde\theta_{I,J}(P^J_I)^n
1850	      = z \cdot (P^I_J)^n \cdot \tilde\theta_{I,J}(P^J_I)^n
1851	      = z \cdot \bigl(P^I_J \cdot \tilde\theta_{I,J}(P^J_I)\bigr)^n
1852	      = z,
1853	  \]
