2170	% (references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L865-L891.)
2171	\begin{proof}
2172	  \uses{def:gr_glued_scheme, lem:gr_separated, def:gr_transition}
2173	  Since \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\) is of finite type
2174	  (\cref{def:gr_glued_scheme}) and separated (\cref{lem:gr_separated}), and
2175	  \(\mathbb{Z}\) is Noetherian, properness follows from the valuative criterion
2176	  for discrete valuation rings: it suffices to show that every solid diagram
2177	  \[
2178	    \begin{array}{ccc}
2179	      \Spec K & \xrightarrow{\ \varphi\ } & \mathrm{Gr}(r,d) \\
2180	      \downarrow & & \downarrow \pi \\
2181	      \Spec R & \longrightarrow & \Spec \mathbb{Z}
2182	    \end{array}
2183	  \]
2184	  with \(R\) a discrete valuation ring, \(K = \operatorname{Frac}(R)\) and
2185	  valuation \(\nu : K \to \mathbb{Z} \cup \{\infty\}\), admits a unique diagonal
2186	  filler \(\Spec R \to \mathrm{Gr}(r,d)\).
2187	
2188	  \emph{Existence.} The morphism \(\varphi : \Spec K \to \mathrm{Gr}(r,d)\) lands
2189	  in some chart \(U^I\) (\(\Spec K\) has one point), so it is given by a ring map
2190	  \(f : \mathbb{Z}[X^I] \to K\). Among the \(\binom{r}{d}\) minors choose \(J\)
2191	  with \(\nu(f(P^I_J))\) minimal. Because \(P^I_I = 1\) gives \(f(P^I_I) = 1\)
2192	  with \(\nu = 0\), the minimum satisfies \(\nu(f(P^I_J)) \le 0\); in particular
2193	  \(f(P^I_J) \ne 0\), so \(f(X^I_J) \in \mathrm{GL}_d(K)\) is invertible over
2194	  \(K\). Define
2195	  \[
2196	    g : \mathbb{Z}[X^J] \longrightarrow K, \qquad
2197	    g(X^J) = f\bigl((X^I_J)^{-1} X^I\bigr) ;
2198	  \]
2199	  this is the composite of \(\theta_{I,J}\) (\cref{def:gr_transition}) with
2200	  \(f\), so \(g\) defines the same \(K\)-point \(\varphi\), now exhibited as
2201	  landing in \(U^J\).
2202	
2203	  We show every entry \(g(x^J_{p,q})\) lies in \(R\), i.e.\ has \(\nu \ge 0\).
2204	  First, for any size-\(d\) subset \(K' \subseteq \{1,\dots,r\}\) the \(K'\)-minor
2205	  of \((X^I_J)^{-1} X^I\) is \((X^I_J)^{-1} X^I_{K'}\), so
2206	  \[
2207	    g(P^J_{K'}) = \det f\bigl((X^I_J)^{-1} X^I_{K'}\bigr)
2208	    = \frac{f(P^I_{K'})}{f(P^I_J)},
2209	    \qquad
2210	    \nu(g(P^J_{K'})) = \nu(f(P^I_{K'})) - \nu(f(P^I_J)) \ge 0
2211	  \]
2212	  by minimality of \(\nu(f(P^I_J))\). Now the \(J\)-minor \(X^J_J\) of \(X^J\) is
2213	  the identity, so by cofactor expansion each individual entry
2214	  \(x^J_{p,q}\) (with \(q \notin J\)) equals, up to sign, the minor
2215	  \(P^J_{K'}\) for \(K' = (J \setminus \{j_p\}) \cup \{q\}\) -- the \(d \times d\)
2216	  determinant obtained by replacing the \(p\)-th identity column of \(X^J_J\) by
2217	  the column \(q\). Hence \(\nu(g(x^J_{p,q})) = \nu(g(P^J_{K'})) \ge 0\) for all
2218	  entries, and the entries with \(q \in J\) are \(0\) or \(1\). Therefore
2219	  \(g(\mathbb{Z}[X^J]) \subseteq R\), so \(g\) factors uniquely as
2220	  \(\mathbb{Z}[X^J] \to R \hookrightarrow K\). The corresponding morphism
2221	  \(\Spec R \to U^J \hookrightarrow \mathrm{Gr}(r,d)\) restricts to \(\varphi\)
2222	  over \(\Spec K\) and lies over \(\Spec \mathbb{Z}\), providing the filler.
2223	
2224	  \emph{Uniqueness.} Any two fillers agree over the generic point \(\Spec K\)
2225	  and, \(\mathrm{Gr}(r,d)\) being separated over \(\mathbb{Z}\)
2226	  (\cref{lem:gr_separated}), two morphisms \(\Spec R \to \mathrm{Gr}(r,d)\)
2227	  agreeing on the schematically dense open \(\Spec K\) coincide. This verifies
2228	  the valuative criterion, so \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\) is
2229	  proper.
2230	\end{proof}
2231	
2232	\section{Out of scope}
2233	\label{sec:gr_out_of_scope}
2234	
2235	This chapter constructs the Grassmannian \emph{scheme} \(\mathrm{Gr}(r,d)\) over
2236	the absolute base \(\mathbb{Z}\) and establishes its smoothness, separatedness
2237	and properness. The following constructions are deferred to later chapters and
2238	are not treated here:
2239	\begin{itemize}
2240	  \item \textbf{The tautological/universal quotient} \(u : \mathcal{O}^{\oplus
2241	    r}_{\mathrm{Gr}(r,d)} \twoheadrightarrow \mathcal{U}\) and the determinant
2242	    line bundle \(\det \mathcal{U}\) with its Pl\"ucker embedding.
2243	  \item \textbf{The functor-of-points representability} of \(\mathrm{Gr}(r,d)\)
2244	    -- that it represents \(\mathrm{Grass}(r,d) =
2245	    \Quot^{d,\mathcal{O}_{\mathbb{Z}}}_{\oplus^r \mathcal{O}_{\mathbb{Z}} /
2246	    \mathbb{Z} / \mathbb{Z}}\); this is blueprinted as
2247	    \cref{thm:grassmannian_representable} in
2248	    \cref{chap:Picard_QuotScheme}.
2249	  \item \textbf{The relative version over a general base \(S\)} with a locally
2250	    free sheaf \(V\) of rank \(r\): the scheme \(\mathrm{Gr}_S(V,d)\) obtained by
2251	    base change and gluing over a trivialising cover of \(V\). The
2252	    absolute-over-\(\mathbb{Z}\) construction of this chapter is the input to
2253	    that base change.
2254	\end{itemize}

